import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { tripsAPI } from '../services/api';

const EMOJIS = ['✈️', '🌴', '🏔️', '🏖️', '🗼', '🏯', '🗽', '🏜️', '🌉', '🏙️', '🏕️', '🏟️', '🎡'];
const GRADIENTS = [
  { label: 'Sunset Red', value: 'from-red-400 to-orange-500' },
  { label: 'Emerald Green', value: 'from-teal-400 to-emerald-500' },
  { label: 'Ocean Blue', value: 'from-blue-400 to-indigo-500' },
  { label: 'Orchid Purple', value: 'from-purple-400 to-pink-500' },
  { label: 'Golden Amber', value: 'from-amber-400 to-orange-500' },
];

export default function MyTrips() {
  const navigate = useNavigate();
  const location = useLocation();
  const [trips, setTrips] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  // Modal state
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    destination: '',
    startDate: '',
    endDate: '',
    budget: '',
    emoji: '✈️',
    gradient: 'from-teal-400 to-emerald-500',
  });
  const [modalError, setModalError] = useState('');
  const [creating, setCreating] = useState(false);

  // Filters state
  const [filter, setFilter] = useState('all'); // 'all' | 'active' | 'planning' | 'completed'
  const [searchQuery, setSearchQuery] = useState('');

  const fetchTrips = async () => {
    try {
      const data = await tripsAPI.getAll();
      setTrips(data);
    } catch (err) {
      console.error(err);
      setError('Failed to fetch trips. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchTrips();
  }, []);

  // Check if we should open create modal on mount
  useEffect(() => {
    const params = new URLSearchParams(location.search);
    if (params.get('create') === 'true') {
      setIsModalOpen(true);
      // clean up URL
      navigate('/trips', { replace: true });
    }
  }, [location.search, navigate]);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleCreateTrip = async (e) => {
    e.preventDefault();
    setModalError('');

    const { name, destination, startDate, endDate, budget } = formData;
    if (!name || !destination || !startDate || !endDate) {
      setModalError('Please fill in all required fields.');
      return;
    }

    if (new Date(startDate) > new Date(endDate)) {
      setModalError('Start date cannot be after the end date.');
      return;
    }

    setCreating(true);
    try {
      await tripsAPI.create({
        ...formData,
        budget: Number(budget) || 0,
      });
      setIsModalOpen(false);
      setFormData({
        name: '',
        destination: '',
        startDate: '',
        endDate: '',
        budget: '',
        emoji: '✈️',
        gradient: 'from-teal-400 to-emerald-500',
      });
      fetchTrips();
    } catch (err) {
      console.error(err);
      setModalError(err.response?.data?.message || 'Failed to create trip. Please try again.');
    } finally {
      setCreating(false);
    }
  };

  // Filter & Search logic
  const filteredTrips = trips.filter((trip) => {
    const matchesSearch =
      trip.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      trip.destination.toLowerCase().includes(searchQuery.toLowerCase());

    if (!matchesSearch) return false;

    if (filter === 'active') return trip.progress > 0 && trip.progress < 100;
    if (filter === 'planning') return trip.progress === 0;
    if (filter === 'completed') return trip.progress === 100;
    return true;
  });

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[80vh]">
        <div className="w-10 h-10 border-4 border-primary-500 border-t-transparent rounded-full animate-spin" />
      </div>
    );
  }

  return (
    <div className="p-8 max-w-7xl mx-auto">
      {/* Top Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-8">
        <div>
          <h1 className="font-display font-bold text-3xl text-gray-900">My Trips</h1>
          <p className="text-gray-500 mt-1">Manage and plan all your travel adventures.</p>
        </div>
        <button
          onClick={() => setIsModalOpen(true)}
          className="inline-flex items-center justify-center gap-2 bg-gradient-to-r from-primary-600 to-emerald-500 text-white px-5 py-2.5 rounded-xl text-sm font-semibold shadow-lg shadow-primary-500/25 hover:shadow-xl hover:-translate-y-0.5 transition-all"
        >
          <span>+</span> Plan a New Trip
        </button>
      </div>

      {error && (
        <div className="mb-6 p-4 bg-red-50 border border-red-200 text-red-600 rounded-xl text-sm">
          {error}
        </div>
      )}

      {/* Filter and Search Bar */}
      <div className="flex flex-col md:flex-row items-center justify-between gap-4 mb-8">
        {/* Search */}
        <div className="relative w-full md:w-80">
          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400">🔍</span>
          <input
            type="text"
            placeholder="Search trips or destinations..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-xl bg-white focus:ring-2 focus:ring-primary-200 focus:border-primary-500 text-sm transition-all"
          />
        </div>

        {/* Filter Tabs */}
        <div className="flex bg-gray-100 rounded-xl p-1 w-full md:w-auto overflow-x-auto">
          {[
            { label: 'All Trips', value: 'all' },
            { label: 'Active', value: 'active' },
            { label: 'Planning', value: 'planning' },
            { label: 'Completed', value: 'completed' },
          ].map((tab) => (
            <button
              key={tab.value}
              onClick={() => setFilter(tab.value)}
              className={`px-4 py-2 text-xs font-semibold rounded-lg transition-all capitalize whitespace-nowrap
                ${filter === tab.value
                  ? 'bg-white text-primary-600 shadow-sm'
                  : 'text-gray-500 hover:text-gray-700'
                }`}
            >
              {tab.label}
            </button>
          ))}
        </div>
      </div>

      {/* Trips Grid */}
      {filteredTrips.length === 0 ? (
        <div className="text-center py-16 bg-white border border-gray-100 rounded-3xl shadow-sm">
          <p className="text-4xl mb-3">🧭</p>
          <h3 className="font-display font-bold text-lg text-gray-800 mb-1">No trips found</h3>
          <p className="text-sm text-gray-400 max-w-sm mx-auto">
            Try adjusting your filters, or start planning a brand new adventure today.
          </p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredTrips.map((trip) => (
            <div
              key={trip._id}
              onClick={() => navigate(`/trips/${trip._id}`)}
              className="bg-white rounded-3xl border border-gray-100 shadow-sm overflow-hidden hover:shadow-xl transition-all hover:-translate-y-1 cursor-pointer flex flex-col justify-between"
            >
              <div>
                {/* Header Banner */}
                <div className={`h-24 bg-gradient-to-br ${trip.gradient || 'from-primary-500 to-emerald-500'} p-4 relative flex items-end`}>
                  <div className="absolute top-4 right-4 bg-white/20 backdrop-blur-md px-3 py-1 rounded-full text-white text-[10px] font-semibold border border-white/20">
                    {trip.progress > 0 && trip.progress < 100
                      ? 'Active'
                      : trip.progress === 100
                        ? 'Completed'
                        : 'Planning'}
                  </div>
                  <div className="w-12 h-12 rounded-2xl bg-white shadow-md flex items-center justify-center text-2xl translate-y-6">
                    {trip.emoji || '✈️'}
                  </div>
                </div>

                <div className="p-6 pt-8">
                  <h3 className="font-display font-bold text-xl text-gray-800 line-clamp-1">{trip.name}</h3>
                  <p className="text-xs text-gray-400 mt-1 flex items-center gap-1">
                    <span>📍</span> {trip.destination}
                  </p>
                  <p className="text-xs text-gray-500 mt-2 font-medium">
                    📅 {new Date(trip.startDate).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })} – {new Date(trip.endDate).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}
                  </p>

                  {/* Progress Bar */}
                  <div className="mt-5">
                    <div className="flex justify-between items-center mb-1 text-[10px] font-medium text-gray-400">
                      <span>Trip Progress</span>
                      <span>{trip.progress}%</span>
                    </div>
                    <div className="w-full bg-gray-100 rounded-full h-1.5">
                      <div
                        className="bg-gradient-to-r from-primary-500 to-emerald-500 h-1.5 rounded-full transition-all"
                        style={{ width: `${trip.progress}%` }}
                      />
                    </div>
                  </div>
                </div>
              </div>

              {/* Stats Footer */}
              <div className="px-6 py-4 bg-gray-50 border-t border-gray-100 flex items-center justify-between text-xs text-gray-500">
                <div>
                  <span className="text-gray-400">Budget:</span> <strong className="text-gray-700">₹{trip.budget?.toLocaleString()}</strong>
                </div>
                <div>
                  <span className="text-gray-400">Crew:</span> <strong className="text-gray-700">{trip.memberCount || 1}</strong>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Creation Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl border border-gray-100 overflow-hidden animate-scale-up">
            <div className="h-2 w-full bg-gradient-to-r from-primary-500 via-primary-600 to-emerald-400" />
            <div className="p-6">
              <div className="flex justify-between items-center mb-4">
                <h2 className="font-display font-bold text-2xl text-gray-800">Plan a New Adventure</h2>
                <button
                  onClick={() => setIsModalOpen(false)}
                  className="text-gray-400 hover:text-gray-600 text-xl font-bold p-1"
                >
                  ✕
                </button>
              </div>

              {modalError && (
                <div className="mb-4 p-3 bg-red-50 border border-red-200 text-red-600 rounded-xl text-xs flex items-center gap-1">
                  <span>⚠️</span> {modalError}
                </div>
              )}

              <form onSubmit={handleCreateTrip} className="space-y-4">
                <div>
                  <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">Trip Name *</label>
                  <input
                    type="text"
                    name="name"
                    value={formData.name}
                    onChange={handleInputChange}
                    placeholder="e.g. Summer Beach Party, Winter Trek"
                    className="w-full px-4 py-2.5 border border-gray-200 rounded-xl focus:ring-2 focus:ring-primary-200 focus:border-primary-500 text-sm"
                    required
                  />
                </div>

                <div>
                  <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">Destination *</label>
                  <input
                    type="text"
                    name="destination"
                    value={formData.destination}
                    onChange={handleInputChange}
                    placeholder="e.g. Goa, Ladakh, Tokyo"
                    className="w-full px-4 py-2.5 border border-gray-200 rounded-xl focus:ring-2 focus:ring-primary-200 focus:border-primary-500 text-sm"
                    required
                  />
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">Start Date *</label>
                    <input
                      type="date"
                      name="startDate"
                      value={formData.startDate}
                      onChange={handleInputChange}
                      className="w-full px-4 py-2.5 border border-gray-200 rounded-xl focus:ring-2 focus:ring-primary-200 focus:border-primary-500 text-sm"
                      required
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">End Date *</label>
                    <input
                      type="date"
                      name="endDate"
                      value={formData.endDate}
                      onChange={handleInputChange}
                      className="w-full px-4 py-2.5 border border-gray-200 rounded-xl focus:ring-2 focus:ring-primary-200 focus:border-primary-500 text-sm"
                      required
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">Budget (INR)</label>
                  <input
                    type="number"
                    name="budget"
                    value={formData.budget}
                    onChange={handleInputChange}
                    placeholder="e.g. 25000"
                    className="w-full px-4 py-2.5 border border-gray-200 rounded-xl focus:ring-2 focus:ring-primary-200 focus:border-primary-500 text-sm"
                  />
                </div>

                {/* Emoji Selector */}
                <div>
                  <label className="block text-xs font-semibold text-gray-500 uppercase mb-1.5">Choose Cover Emoji</label>
                  <div className="flex flex-wrap gap-2 max-h-24 overflow-y-auto p-1.5 bg-gray-50 border border-gray-100 rounded-xl">
                    {EMOJIS.map((emoji) => (
                      <button
                        key={emoji}
                        type="button"
                        onClick={() => setFormData((prev) => ({ ...prev, emoji }))}
                        className={`w-9 h-9 text-lg rounded-lg flex items-center justify-center hover:bg-gray-150 transition-colors
                          ${formData.emoji === emoji ? 'bg-primary-100 border border-primary-300' : 'bg-white border border-gray-200'}`}
                      >
                        {emoji}
                      </button>
                    ))}
                  </div>
                </div>

                {/* Gradient Selector */}
                <div>
                  <label className="block text-xs font-semibold text-gray-500 uppercase mb-1.5">Choose Theme Gradient</label>
                  <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
                    {GRADIENTS.map((grad) => (
                      <button
                        key={grad.value}
                        type="button"
                        onClick={() => setFormData((prev) => ({ ...prev, gradient: grad.value }))}
                        className={`px-3 py-2 text-[10px] font-semibold rounded-lg text-white text-center bg-gradient-to-br ${grad.value}
                          ${formData.gradient === grad.value ? 'ring-4 ring-primary-500/30 border-2 border-white' : 'border border-transparent'}`}
                      >
                        {grad.label}
                      </button>
                    ))}
                  </div>
                </div>

                <div className="pt-4 flex gap-3">
                  <button
                    type="button"
                    onClick={() => setIsModalOpen(false)}
                    className="flex-1 py-3 border border-gray-200 text-gray-500 font-semibold text-sm rounded-xl hover:bg-gray-50 transition-all"
                  >
                    Cancel
                  </button>
                  <button
                    type="submit"
                    disabled={creating}
                    className="flex-1 py-3 bg-gradient-to-r from-primary-600 to-emerald-500 text-white font-semibold text-sm rounded-xl
                      hover:from-primary-700 hover:to-emerald-600 shadow-lg shadow-primary-500/25 transition-all flex items-center justify-center gap-2"
                  >
                    {creating ? (
                      <>
                        <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                        Creating...
                      </>
                    ) : (
                      'Create Trip'
                    )}
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
